type InitiateDisputeInput = {
  order_id: string
  initiator_id: string
  category: string
  description: string
}

export const initiateDisputeWorkflow = createWorkflow(
  "initiate-dispute",
  (input: InitiateDisputeInput) => {
    validateDisputeEligibilityStep({
      order_id: input.order_id,
      initiator_id: input.initiator_id,
    })

    const vendorResult = resolveOrderVendorStep({ order_id: input.order_id })

    const dispute = createDisputeStep(
      transform({ input, vendorResult }, ({ input, vendorResult }) => ({
        order_id: input.order_id,
        initiator_id: input.initiator_id,
        vendor_id: vendorResult.vendor_id,
        category: input.category,
        description: input.description,
      }))
    )

    appendTimelineEventStep(
      transform({ dispute, input }, ({ dispute, input }) => ({
        dispute_id: (dispute as any).id,
        event_type: "opened",
        actor_id: input.initiator_id,
        actor_role: "buyer",
        metadata: { category: input.category },
      }))
    )

    return new WorkflowResponse(dispute)
  }
)

import { createWorkflow, WorkflowResponse, createStep, StepResponse } from "@medusajs/framework/workflows-sdk"
import { DISPUTE_MODULE, DisputeModuleService, DisputeStatus, DisputeDecision } from "@mercurjs/dispute"
import { ContainerRegistrationKeys, MedusaError } from "@medusajs/framework/utils"
import { appendTimelineEventStep } from "../steps/append-timeline-event"

const updateDisputeDecisionStep = createStep(
  "update-dispute-decision",
  async (
    input: {
      dispute_id: string
      mediator_id: string
      decision: string
      decision_reasoning: string
      compensation_amount?: number
    },
    { container }
  ) => {
    const disputeService = container.resolve<DisputeModuleService>(DISPUTE_MODULE)
    const query = container.resolve(ContainerRegistrationKeys.QUERY)

    const { data: [dispute] } = await query.graph({
      entity: "dispute",
      fields: ["id", "status", "mediator_id"],
      filters: { id: input.dispute_id },
    })

    if (!dispute) {
      throw new MedusaError(MedusaError.Types.NOT_FOUND, "Dispute not found")
    }

    if (dispute.mediator_id !== input.mediator_id) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        "Only the assigned mediator can render a decision"
      )
    }

    if (
      ![DisputeStatus.UNDER_REVIEW, DisputeStatus.APPEALED].includes(
        dispute.status as DisputeStatus
      )
    ) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        "Dispute must be under review or appealed to render a decision"
      )
    }

    const appealBy = new Date()
    appealBy.setDate(appealBy.getDate() + 7)

    const updated = await disputeService.updateDisputes({
      id: input.dispute_id,
      decision: input.decision as DisputeDecision,
      decision_reasoning: input.decision_reasoning,
      compensation_amount: input.compensation_amount ?? null,
      status: DisputeStatus.DECIDED,
      decided_at: new Date(),
      appeal_by: appealBy,
    })

    return new StepResponse(updated, { dispute_id: input.dispute_id, previous_status: dispute.status })
  },
  async (compensationInput: { dispute_id: string; previous_status: string }, { container }) => {
    const disputeService = container.resolve<DisputeModuleService>(DISPUTE_MODULE)
    await disputeService.updateDisputes({
      id: compensationInput.dispute_id,
      status: compensationInput.previous_status as DisputeStatus,
      decision: null,
      decided_at: null,
    })
  }
)

type RenderDecisionInput = {
  dispute_id: string
  mediator_id: string
  decision: string
  decision_reasoning: string
  compensation_amount?: number
}

export const renderDecisionWorkflow = createWorkflow(
  "render-dispute-decision",
  (input: RenderDecisionInput) => {
    const dispute = updateDisputeDecisionStep(input)

    appendTimelineEventStep({
      dispute_id: input.dispute_id,
      event_type: "decided",
      actor_id: input.mediator_id,
      actor_role: "mediator",
      metadata: {
        decision: input.decision,
        compensation_amount: input.compensation_amount,
      },
    })

    return new WorkflowResponse(dispute)
  }
)

