import { createStep, StepResponse } from "@medusajs/framework/workflows-sdk"
import { ContainerRegistrationKeys, MedusaError } from "@medusajs/framework/utils"

export const DISPUTE_ELIGIBILITY_WINDOW_DAYS = 30

export async function checkDisputeEligibility(
  input: { order_id: string; initiator_id: string },
  query: { graph: (opts: any) => Promise<{ data: any[] }> }
): Promise<{ order: any }> {
  const { data: [order] } = await query.graph({
    entity: "order",
    fields: ["id", "customer_id", "status", "fulfilled_at"],
    filters: { id: input.order_id },
  })

  if (!order) {
    throw new MedusaError(
      MedusaError.Types.NOT_FOUND,
      `Order ${input.order_id} not found`
    )
  }

  if (order.customer_id !== input.initiator_id) {
    throw new MedusaError(
      MedusaError.Types.NOT_ALLOWED,
      "You can only open disputes for your own orders"
    )
  }

  if (order.status !== "fulfilled") {
    throw new MedusaError(
      MedusaError.Types.NOT_ALLOWED,
      "Disputes can only be opened on fulfilled orders"
    )
  }

  if (!order.fulfilled_at) {
    throw new MedusaError(
      MedusaError.Types.INVALID_DATA,
      "Cannot open dispute: order fulfillment date not recorded"
    )
  }

  const fulfillmentDate = new Date(order.fulfilled_at)
  const cutoff = new Date(fulfillmentDate)
  cutoff.setDate(cutoff.getDate() + DISPUTE_ELIGIBILITY_WINDOW_DAYS)

  if (new Date() > cutoff) {
    throw new MedusaError(
      MedusaError.Types.NOT_ALLOWED,
      "The dispute window for this order has expired (30 days from fulfillment)"
    )
  }

  const { data: existingDisputes } = await query.graph({
    entity: "dispute",
    fields: ["id", "status"],
    filters: { order_id: input.order_id },
  })

  const activeDispute = existingDisputes.find(
    (d: any) => d.status !== "closed"
  )
  if (activeDispute) {
    throw new MedusaError(
      MedusaError.Types.NOT_ALLOWED,
      "An active dispute already exists for this order"
    )
  }

  return { order }
}

export const validateDisputeEligibilityStep = createStep(
  "validate-dispute-eligibility",
  async (
    input: { order_id: string; initiator_id: string },
    { container }
  ) => {
    const query = container.resolve(ContainerRegistrationKeys.QUERY)
    const result = await checkDisputeEligibility(input, query)
    return new StepResponse(result)
  }
)

