  NOT_AS_DESCRIBED = "not_as_described",
  WRONG_ITEM = "wrong_item",
  OTHER = "other",
}

export enum DisputeStatus {
  OPEN = "open",
  AWAITING_VENDOR = "awaiting_vendor",
  UNDER_REVIEW = "under_review",
  DECIDED = "decided",
  APPEALED = "appealed",
  STRIPE_HOLD = "stripe_hold",
  CLOSED = "closed",
}

export enum DisputeDecision {
  BUYER_WINS = "buyer_wins",
  VENDOR_WINS = "vendor_wins",
  PARTIAL = "partial",
}

export const Dispute = model.define("dispute", {
  id: model.id({ prefix: "disp" }).primaryKey(),
  order_id: model.text(),
  initiator_id: model.text(),
  vendor_id: model.text(),
  category: model
    .enum(Object.values(DisputeCategory))
    .default(DisputeCategory.OTHER),
  description: model.text(),
  status: model
    .enum(Object.values(DisputeStatus))
    .default(DisputeStatus.OPEN),

  // Response windows
  vendor_respond_by: model.dateTime().nullable(),
  mediator_decide_by: model.dateTime().nullable(),
  appeal_by: model.dateTime().nullable(),

  // Assignment
  mediator_id: model.text().nullable(),

  // Decision
  decision: model.enum(Object.values(DisputeDecision)).nullable(),
  decision_reasoning: model.text().nullable(),
  decided_at: model.dateTime().nullable(),
  compensation_amount: model.bigNumber().nullable(),

  // Stripe integration
  stripe_charge_id: model.text().nullable(),
  stripe_dispute_paused: model.boolean().default(false),

  // Vendor response
  vendor_response: model.text().nullable(),

  // Appeal
  appeal_reason: model.text().nullable(),
  appeal_mediator_id: model.text().nullable(),
  appeal_decision: model.text().nullable(),
  appeal_decided_at: model.dateTime().nullable(),

  // Relations
  evidence: model.hasMany(() => DisputeEvidence, {
    mappedBy: "dispute",
  }),
  messages: model.hasMany(() => DisputeMessage, {
    mappedBy: "dispute",
  }),
  timeline: model.hasMany(() => DisputeTimeline, {
    mappedBy: "dispute",
  }),
})
